import { Plugin, TFile, normalizePath, Notice } from "obsidian";

export interface ProcessorPlugin extends Plugin {
  saveSettings(): Promise<void>;
}
import {
  AttachmentHubSettings,
  isImage,
  isVideo,
  isHeicExt,
  isPasted,
  getExtOverride,
  getOverride,
  saveOrigName,
} from "./settings";
import { convertVideoFile, isAnimatedHeic, VideoTarget } from "./ffmpeg-handler";
import { convertImage, ImageFormat, ResizeOpts } from "./image-processor";
import { decodeHeic } from "./heic-handler";
import {
  pDir, pBase, pExt, pStem, pJoin,
  relative,
  md5sum,
  computeAttachPath,
  computeAttachName,
  dedup,
  parseFM, writeFM,
  stripLink, fmtPath,
  ensureFolder,
} from "./utils";
import { pJoin as join } from "./path-utils";

export class AttachmentProcessor {
  private plugin: ProcessorPlugin;
  private settings: AttachmentHubSettings;
  private _writing: Set<string>;

  constructor(plugin: ProcessorPlugin, settings: AttachmentHubSettings, writing: Set<string>) {
    this.plugin = plugin;
    this.settings = settings;
    this._writing = writing;
  }

  async processNewAttach(attach: TFile, source: TFile): Promise<void> {
    if (source.parent && this.isExcluded(source.parent.path)) return;
    const setting = getOverride(this.settings, source.path);
    const eo = getExtOverride(attach.extension, setting);
    if (!eo && !isImage(attach.extension) && !isVideo(attach.extension) && !isHeicExt(attach.extension) && !isPasted(attach)) return;

    // ── Conversion: only modify binary data, no rename yet ──
    let convertedExt: string | null = null;
    const shouldTryFFmpeg = this.settings.ffmpegPath && this.settings.videoConvertTo !== "disabled";
    const shouldConvertImage = this.settings.convertTo !== "disabled";

    if (isVideo(attach.extension)) {
      if (shouldTryFFmpeg) {
        const result = await this._convertVideoData(attach);
        if (result) {
          await this.plugin.app.vault.modifyBinary(attach, result.data);
          convertedExt = result.ext;
        }
      }
    } else if (isHeicExt(attach.extension)) {
      const animated = shouldTryFFmpeg && (await this._isHeicAnimated(attach));
      if (animated) {
        const result = await this._convertVideoData(attach);
        if (result) {
          await this.plugin.app.vault.modifyBinary(attach, result.data);
          convertedExt = result.ext;
        }
      } else if (shouldConvertImage) {
        const result = await this._convertImageData(attach);
        if (result) {
          await this.plugin.app.vault.modifyBinary(attach, result.data);
          convertedExt = result.ext;
        }
      }
    } else if (shouldConvertImage && isImage(attach.extension)) {
      const result = await this._convertImageData(attach);
      if (result) {
        await this.plugin.app.vault.modifyBinary(attach, result.data);
        convertedExt = result.ext;
      }
    }

    // Use new extension if converted, otherwise keep original
    const finalExt = convertedExt || attach.extension;

    const obsFolder = (this.plugin.app as unknown).getConfig("attachmentFolderPath") || "";
    const attachPath = computeAttachPath(source, finalExt, setting, this.settings.dateFormat, obsFolder);
    let attachName = await computeAttachName(
      source, attach, setting, this.settings.dateFormat, this.plugin.app.vault.adapter,
    );
    attachName += "." + finalExt;

    await ensureFolder(this.plugin.app.vault.adapter, attachPath);
    const dedupName = await dedup(attachName, attachPath, this.plugin.app.vault.adapter);
    const dst = normalizePath(pJoin(attachPath, dedupName));

    const oldPath = attach.path;
    const origBasename = pStem(attach.path);
    try {
      await this.plugin.app.fileManager.renameFile(attach, dst);
    } catch (e) {
      console.error("[AttachHub] rename failed:", e);
      return;
    }

    // fileManager.renameFile relies on resolvedLinks which may not be up-to-date
    // after a fresh paste. Manually patch the source note to ensure the link is correct.
    await this._patchSourceNoteLink(source, oldPath, dst);

    const msg = convertedExt
      ? `已转换并重命名 ${pBase(oldPath)} → ${dedupName}`
      : `已重命名 ${pBase(oldPath)} → ${dedupName}`;
    if (!this.settings.disableNotification) new Notice(msg);

    const renamedFile = this.plugin.app.vault.getAbstractFileByPath(dst);
    if (renamedFile instanceof TFile) {
      const md5Val = await md5sum(this.plugin.app.vault.adapter, renamedFile);
      saveOrigName(this.settings, setting, pExt(dst), { n: origBasename, md5: md5Val });
      await this.plugin.saveSettings();
    }

    await this._updateFMAfterRename(source, oldPath, dst);
  }

  /**
   * Convert video data via system FFmpeg. Returns raw result, does NOT touch the vault file.
   */
  private async _convertVideoData(attach: TFile): Promise<{ data: ArrayBuffer; ext: string } | null> {
    try {
      const basePath = (this.plugin.app.vault.adapter as unknown).basePath as string;
      if (!basePath) return null;
      const absPath = join(basePath, attach.path);
      return await convertVideoFile(absPath, attach.extension, {
        ffmpegPath: this.settings.ffmpegPath,
        target: this.settings.videoConvertTo as VideoTarget,
        quality: this.settings.quality,
        resizeValue: this.settings.resizeMode !== "disabled" ? this.settings.resizeValue : 0,
      });
    } catch (e: unknown) {
      console.error("[AttachHub] Video conversion error:", e);
      return null;
    }
  }

  /**
   * Convert image data via Canvas API (HEIC decoded first).
   * For HEIC: native decode → heic2any → FFmpeg fallback.
   * Returns raw result, does NOT touch the vault file.
   */
  private async _convertImageData(attach: TFile): Promise<{ data: ArrayBuffer; ext: string } | null> {
    const target = this.settings.convertTo as ImageFormat;
    if (target === "disabled") return null;
    const ext = attach.extension.toLowerCase();
    if (ext === target || (target === "jpg" && /^jpe?g$/.test(ext))) return null;

    try {
      if (isHeicExt(attach.extension)) {
        const imgData = await this.plugin.app.vault.readBinary(attach);
        const decoded = await decodeHeic(imgData);
        if (!decoded) {
          console.warn("[AttachHub] HEIC decode failed, skipping conversion");
          return null;
        }
        const resize: ResizeOpts = {
          mode: (this.settings.resizeMode || "disabled") as ResizeOpts["mode"],
          value: this.settings.resizeValue || 0,
        };
        return await convertImage(decoded, target, this.settings.quality, resize);
      }

      // Regular image (JPG/PNG/BMP/GIF/etc.) — Canvas API
      const imgData = await this.plugin.app.vault.readBinary(attach);
      const resize: ResizeOpts = {
        mode: (this.settings.resizeMode || "disabled") as ResizeOpts["mode"],
        value: this.settings.resizeValue || 0,
      };
      return await convertImage(imgData, target, this.settings.quality, resize);
    } catch (e: unknown) {
      console.error("[AttachHub] Image conversion error:", e);
      return null;
    }
  }

  private async _isHeicAnimated(attach: TFile): Promise<boolean> {
    try {
      const basePath = (this.plugin.app.vault.adapter as unknown).basePath as string;
      if (!basePath) return false;
      const absPath = join(basePath, attach.path);
      return await isAnimatedHeic(absPath);
    } catch {
      return false;
    }
  }

  /**
   * Directly patch the source note to replace old attachment references with the new path.
   * fileManager.renameFile depends on resolvedLinks which may be stale right after a paste,
   * so we do a manual text replacement as a reliable fallback.
   */
  private async _patchSourceNoteLink(source: TFile, oldAttachPath: string, newAttachPath: string): Promise<void> {
    try {
      let content = await this.plugin.app.vault.read(source);
      const oldName = pBase(oldAttachPath);
      const newName = pBase(newAttachPath);
      if (oldName === newName) return;

      const noteDir = pDir(source.path);
      const oldRel = relative(noteDir, oldAttachPath);
      const newRel = relative(noteDir, newAttachPath);

      let changed = false;

      // Wikilink: ![[oldName]] or ![[oldPath]]
      const wikiPatterns = [
        `![[${oldName}]]`,
        `![[${oldAttachPath}]]`,
        `[[${oldName}]]`,
        `[[${oldAttachPath}]]`,
      ];
      for (const pat of wikiPatterns) {
        if (content.includes(pat)) {
          const replacement = pat.startsWith("!") ? `![[${newName}]]` : `[[${newName}]]`;
          content = content.split(pat).join(replacement);
          changed = true;
        }
      }

      // Markdown link: ![...](oldRel) or ![...](encoded)
      const mdPatterns = [oldRel, encodeURI(oldRel), oldName, encodeURI(oldName)];
      for (const p of mdPatterns) {
        const escaped = p.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
        const re = new RegExp(`(!\\[[^\\]]*\\])\\(${escaped}\\)`, "g");
        if (re.test(content)) {
          content = content.replace(re, `$1(${newRel})`);
          changed = true;
        }
      }

      if (changed) {
        this._writing.add(source.path);
        try {
          await this.plugin.app.vault.modify(source, content);
        } finally {
          setTimeout(() => this._writing.delete(source.path), 2000);
        }
      }
    } catch (e) {
      console.error("[AttachHub] patch source note failed:", e);
    }
  }

  private async _updateFMAfterRename(source: TFile, oldAttachPath: string, newAttachPath: string): Promise<void> {
    let content: string;
    try { content = await this.plugin.app.vault.read(source); } catch (_) { return; }
    const fm = parseFM(content);
    if (!fm) return;
    const noteDir = pDir(source.path);
    const fmt = this.settings.pathFormat || "plain";
    const upd: Record<string, string> = {};
    for (const field of this.settings.trackedFields) {
      const val = fm[field];
      if (typeof val !== "string" || !val) continue;
      const plain = stripLink(val) || val;
      const resolved = this.resolve(noteDir, plain);
      if (resolved && normalizePath(resolved) === normalizePath(oldAttachPath)) {
        upd[field] = fmtPath(relative(noteDir, newAttachPath), fmt);
      }
    }
    if (Object.keys(upd).length) {
      this._writing.add(source.path);
      try { await writeFM(this.plugin.app, source, upd); } finally {
        setTimeout(() => this._writing.delete(source.path), 2000);
      }
      const newFM = await this.getFM(source);
      if (newFM) this.updateNoteIndex(source.path, this.extractResolvedPaths(newFM, this.settings.trackedFields, noteDir));
    }
  }

  // Helper methods that will be implemented in the main plugin
  private isExcluded(dirPath: string): boolean {
    for (const ep of this.settings.excludePathsArray || []) {
      if (!ep) continue;
      if (this.settings.excludeSubpaths && dirPath.startsWith(ep)) return true;
      if (dirPath === ep) return true;
    }
    return false;
  }

  private resolve(fromDir: string, rel: string): string | null {
    if (!rel || rel.startsWith("http://") || rel.startsWith("https://")) return null;
    const s = fromDir ? fromDir.split("/") : [];
    for (const p of rel.split("/")) {
      if (p === "..") s.pop();
      else if (p !== "." && p) s.push(p);
    }
    return normalizePath(s.join("/"));
  }

  private async getFM(file: TFile): Promise<Record<string, unknown> | null> {
    const c = this.plugin.app.metadataCache.getFileCache(file);
    if (c?.frontmatter) return c.frontmatter;
    try {
      return parseFM(await this.plugin.app.vault.cachedRead(file));
    } catch {
      return null;
    }
  }

  private updateNoteIndex(notePath: string, newMap: Map<string, string> | null): void {
    // This will be implemented in the main plugin
  }

  private extractResolvedPaths(
    fm: Record<string, unknown>,
    trackedFields: string[],
    noteDir: string,
  ): Map<string, string> {
    const result = new Map<string, string>();
    for (const field of trackedFields) {
      const val = fm[field];
      if (typeof val !== "string" || !val) continue;
      const plain = stripLink(val) || val;
      if (plain.startsWith("http://") || plain.startsWith("https://")) continue;
      const resolved = this.resolve(noteDir, plain);
      if (resolved) result.set(field, normalizePath(resolved));
    }
    return result;
  }
}

import { Plugin, TFile, TFolder, App } from "obsidian";
import { AttachmentHubSettings, isNote, isAttach, updateOverridePath, isExcluded, NOTE_EXT } from "./settings";
import { AttachmentProcessor } from "./attachment-processor";
import { FrontmatterSync } from "./frontmatter-sync";
import { IndexManager } from "./index-manager";
import { OverrideModal } from "./modals";
import { debounce } from "./utils";

interface OverridePlugin extends Plugin {
  settings: AttachmentHubSettings;
  saveSettings(): Promise<void>;
}

export class EventHandlers {
  private plugin: OverridePlugin;
  private settings: AttachmentHubSettings;
  private attachmentProcessor: AttachmentProcessor;
  private frontmatterSync: FrontmatterSync;
  private indexManager: IndexManager;
  private _createQ: TFile[];
  private _writing: Set<string>;
  private _modTimers: Record<string, ReturnType<typeof setTimeout>>;
  private _debouncedPasteDetect: (file: TFile) => void;

  constructor(
    plugin: OverridePlugin,
    settings: AttachmentHubSettings,
    attachmentProcessor: AttachmentProcessor,
    frontmatterSync: FrontmatterSync,
    indexManager: IndexManager,
    createQ: TFile[],
    writing: Set<string>,
    modTimers: Record<string, ReturnType<typeof setTimeout>>
  ) {
    this.plugin = plugin;
    this.settings = settings;
    this.attachmentProcessor = attachmentProcessor;
    this.frontmatterSync = frontmatterSync;
    this.indexManager = indexManager;
    this._createQ = createQ;
    this._writing = writing;
    this._modTimers = modTimers;

    // Create debounced version of paste detection
    this._debouncedPasteDetect = debounce((file: TFile) => {
      this._handlePasteDetect(file);
    }, 300);
  }

  registerEvents(): void {
    // File create event
    this.plugin.registerEvent(
      this.plugin.app.vault.on("create", (file) => {
        if (!(file instanceof TFile) || NOTE_EXT.has(file.extension)) return;
        if (Date.now() - file.stat.ctime > 1000) return;
        if (this.matchExt(file.extension, this.settings.excludeExtensionPattern)) return;
        this._createQ.push(file);
      }),
    );

    // File modify event
    this.plugin.registerEvent(
      this.plugin.app.vault.on("modify", (file) => {
        if (!(file instanceof TFile) || !isNote(file) || this._writing.has(file.path)) return;
        if (this._createQ.length > 0) this._debouncedPasteDetect(file);
        if (file.extension === "mdx") {
          if (this._modTimers[file.path]) clearTimeout(this._modTimers[file.path]);
          this._modTimers[file.path] = setTimeout(() => {
            delete this._modTimers[file.path];
            this.frontmatterSync.onMdxModify(file);
          }, 600);
        }
      }),
    );

    // Metadata cache changed event
    this.plugin.registerEvent(
      this.plugin.app.metadataCache.on("changed", (file) => {
        if (!(file instanceof TFile) || !isNote(file) || this._writing.has(file.path)) return;
        if (file.extension === "md") this.frontmatterSync.onFMChange(file);
      }),
    );

    // File rename event
    this.plugin.registerEvent(
      this.plugin.app.vault.on("rename", async (file, oldPath) => {
        const ovr = this.settings.overridePath[oldPath];
        if (ovr) {
          updateOverridePath(this.settings, file.path, oldPath);
          await (this.plugin as unknown).saveSettings();
        }
        if (file instanceof TFile && isNote(file)) {
          this.indexManager.removeNoteFromIndex(oldPath);
          if (file.parent && isExcluded(file.parent.path, this.settings)) return;
          if (this.settings.handleNoteMove) await this.frontmatterSync.handleNoteMove(file, oldPath);
        } else if (file instanceof TFile && isAttach(file) && this.settings.handleAttachmentMove) {
          await this.frontmatterSync.handleAttachRename(file, oldPath);
        }
      }),
    );

    // File delete event
    this.plugin.registerEvent(
      this.plugin.app.vault.on("delete", async (file) => {
        if (isNote(file)) {
          this.indexManager.removeNoteFromIndex(file.path);
          if (this.settings.overridePath[file.path]) {
            delete this.settings.overridePath[file.path];
            await (this.plugin as unknown).saveSettings();
          }
          this._cleanOldAttachFolder(file.path);
          return;
        }
        if (isAttach(file) && this.settings.clearOnDelete) this.frontmatterSync.onAttachDelete(file);
      }),
    );

    // File menu event
    this.plugin.registerEvent(
      this.plugin.app.workspace.on("file-menu", (menu, file) => {
        if ((file instanceof TFile && file.parent && isExcluded(file.parent.path, this.settings)) || isAttach(file))
          return;
        menu.addItem(item => {
          item.setTitle("Override attachment setting").setIcon("image-plus").onClick(() => {
            const s = { ...this.getOverride(this.settings, file.path) };
            new OverrideModal(this.plugin, file as TFile | TFolder, s).open();
          });
        });
      }),
    );
  }

  private async _handlePasteDetect(noteFile: TFile): Promise<void> {
    const f = this._createQ[0];
    if (!f) return;
    try {
      if (!(await this.plugin.app.vault.adapter.exists(f.path))) {
        this._createQ.shift();
        return;
      }
      const content = await this.plugin.app.vault.adapter.read(noteFile.path);
      const link = this.plugin.app.fileManager.generateMarkdownLink(f, noteFile.path);
      const relPath = this.relative(this.pDir(noteFile.path), f.path);
      const found =
        content.includes(link) ||
        content.includes(f.name) ||
        content.includes(relPath) ||
        (noteFile.extension === "canvas" && content.includes(f.path));
      if (found) {
        this._createQ.shift();
        await this.attachmentProcessor.processNewAttach(f, noteFile);
      }
    } catch (_) {}
  }

  private async _cleanOldAttachFolder(notePath: string): Promise<void> {
    const setting = this.getOverride(this.settings, notePath);
    const obsFolder = (this.plugin.app.vault as unknown).getConfig("attachmentFolderPath") || "";
    const noteDir = this.pDir(notePath);
    const sub = this.resolveVars(setting.attachmentPath || "", {
      dateFormat: this.settings.dateFormat,
      noteName: this.pStem(notePath),
      noteDir,
      parentName: this.pBase(noteDir),
    });
    const root = this.getRootPath(noteDir, setting, obsFolder);
    const old = this.normalizePath(this.pJoin(root, sub));
    if (old && (await this.isEmptyFolder(this.plugin.app.vault.adapter, old))) {
      try { await this.plugin.app.vault.adapter.rmdir(old, true); } catch (_) {}
    }
  }

  // Helper methods
  private isNote(f: unknown): f is TFile {
    return isNote(f);
  }

  private isAttach(f: unknown): f is TFile {
    return isAttach(f);
  }

  private isExcluded(dirPath: string, settings: AttachmentHubSettings): boolean {
    return isExcluded(dirPath, settings);
  }

  private matchExt(ext: string, pat: string): boolean {
    return pat ? new RegExp(pat).test(ext) : false;
  }

  private getOverride(settings: AttachmentHubSettings, filePath: string): unknown {
    const op = settings.overridePath;
    if (!op || !Object.keys(op).length) return settings.attachPath;
    if (op[filePath] && op[filePath].type === "FILE") return op[filePath];
    const candidates: [string, unknown][] = [];
    for (const [p, s] of Object.entries(op)) {
      if (s.type === "FOLDER" && filePath.startsWith(p + "/")) candidates.push([p, s]);
    }
    if (candidates.length) {
      candidates.sort((a, b) => b[0].split("/").length - a[0].split("/").length);
      return candidates[0][1];
    }
    return settings.attachPath;
  }

  private pDir(p: string): string {
    const i = p.lastIndexOf("/");
    return i < 0 ? "" : p.substring(0, i);
  }

  private pBase(p: string): string {
    const i = p.lastIndexOf("/");
    return i < 0 ? p : p.substring(i + 1);
  }

  private pStem(p: string): string {
    const b = this.pBase(p), i = b.lastIndexOf(".");
    return i < 0 ? b : b.substring(0, i);
  }

  private pJoin(...parts: string[]): string {
    const s: string[] = [];
    for (const p of parts) {
      for (const seg of p.split("/")) {
        if (seg === "..") s.pop();
        else if (seg && seg !== ".") s.push(seg);
      }
    }
    return s.join("/");
  }

  private normalizePath(p: string): string {
    return (this.plugin.app as unknown).normalizePath(p);
  }

  private relative(fromDir: string, toPath: string): string {
    const f = fromDir ? fromDir.split("/") : [];
    const t = toPath.split("/");
    let c = 0;
    while (c < f.length && c < t.length && f[c] === t[c]) c++;
    const p: string[] = [];
    for (let i = 0; i < f.length - c; i++) p.push("..");
    p.push(...t.slice(c));
    return p.join("/");
  }

  private resolveVars(template: string, ctx: unknown): string {
    const d = (window as unknown).moment
      ? (window as unknown).moment().format(ctx.dateFormat || "YYYYMMDDHHmmssSSS")
      : Date.now().toString();
    return template
      .replace(/\$\{date\}/g, d)
      .replace(/\$\{notename\}/g, ctx.noteName || "")
      .replace(/\$\{notepath\}/g, ctx.noteDir || "")
      .replace(/\$\{parent\}/g, ctx.parentName || "")
      .replace(/\$\{originalname\}/g, ctx.origName || "")
      .replace(/\$\{md5\}/g, ctx.md5 || "");
  }

  private getRootPath(noteDir: string, setting: unknown, obsFolder: string): string {
    switch (setting.saveAttE) {
      case "inFolderBelow":
        return this.normalizePath(setting.attachmentRoot || "");
      case "nextToNote":
        return this.normalizePath(this.pJoin(noteDir, (setting.attachmentRoot || "").replace(/^\.\//, "")));
      default:
        if (!obsFolder || obsFolder === "/") return obsFolder === "/" ? "" : "";
        if (obsFolder === "./") return noteDir;
        if (obsFolder.startsWith("./"))
          return this.normalizePath(this.pJoin(noteDir, obsFolder.replace(/^\.\//, "")));
        return this.normalizePath(obsFolder);
    }
  }

  private async isEmptyFolder(adapter: unknown, p: string): Promise<boolean> {
    if (!p) return false;
    try {
      const l = await adapter.list(p);
      return !l.files.length && !l.folders.length;
    } catch (_) {
      return false;
    }
  }
}

/**
 * FFmpeg handler using system-installed FFmpeg binary.
 * Supports: animated HEIF → WEBP, MP4/MOV → WEBP/GIF, and general video conversion.
 */

import { execFile } from "child_process";
import { promisify } from "util";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";

const execFileAsync = promisify(execFile);
const readFileAsync = promisify(fs.readFile);
const writeFileAsync = promisify(fs.writeFile);
const unlinkAsync = promisify(fs.unlink);
const mkdtempAsync = promisify(fs.mkdtemp);

export type VideoTarget = "webp" | "gif" | "disabled";

export const VIDEO_EXT = new Set(["mp4", "mov", "avi", "mkv", "webm"]);

export function isVideoExt(ext: string): boolean {
  return VIDEO_EXT.has(ext.toLowerCase());
}

/**
 * Detect whether a HEIC/HEIF file contains animation (Live Photo / image sequence).
 * Checks for moov atom or sequence-related ftyp brands.
 * Static HEIC returns false → should use image processor instead of FFmpeg.
 */
export async function isAnimatedHeic(absPath: string): Promise<boolean> {
  const fd = await new Promise<number>((resolve, reject) =>
    fs.open(absPath, "r", (err, fd) => (err ? reject(err) : resolve(fd))),
  );
  try {
    const headerBuf = Buffer.alloc(4096);
    const bytesRead: number = await new Promise((resolve, reject) =>
      fs.read(fd, headerBuf, 0, 4096, 0, (err, n) => (err ? reject(err) : resolve(n))),
    );
    const data = headerBuf.subarray(0, bytesRead);

    // Check ftyp compatible brands for sequence indicators
    if (data.length >= 8) {
      const ftypStart = data.indexOf("ftyp");
      if (ftypStart >= 0 && ftypStart >= 4) {
        const boxSizeOffset = ftypStart - 4;
        const boxSize = data.readUInt32BE(boxSizeOffset);
        const brandEnd = Math.min(boxSizeOffset + boxSize, data.length);
        const brandSection = data.subarray(ftypStart + 4, brandEnd).toString("ascii");
        const seqBrands = ["avis", "msf1", "mif2"];
        for (const sb of seqBrands) {
          if (brandSection.includes(sb)) return true;
        }
      }
    }

    // Scan for 'moov' atom — presence indicates video/animation tracks
    const moovSig = Buffer.from("moov");
    if (data.indexOf(moovSig) >= 0) return true;

    // Also scan a larger portion for moov if file is big
    const statSize: number = await new Promise((resolve, reject) =>
      fs.fstat(fd, (err, st) => (err ? reject(err) : resolve(st.size))),
    );
    if (statSize > 4096) {
      const scanSize = Math.min(65536, statSize);
      const bigBuf = Buffer.alloc(scanSize);
      await new Promise<number>((resolve, reject) =>
        fs.read(fd, bigBuf, 0, scanSize, 0, (err, n) => (err ? reject(err) : resolve(n))),
      );
      if (bigBuf.indexOf(moovSig) >= 0) return true;
    }

    return false;
  } finally {
    fs.closeSync(fd);
  }
}

export async function testFFmpeg(ffmpegPath: string): Promise<string> {
  if (!ffmpegPath) throw new Error("FFmpeg path is empty");
  try {
    const { stdout, stderr } = await execFileAsync(ffmpegPath, ["-version"], { timeout: 5000 });
    const output = stdout || stderr;
    const firstLine = output.split("\n")[0]?.trim();
    if (!firstLine) throw new Error("No output from ffmpeg");
    return firstLine;
  } catch (e: unknown) {
    if (e.code === "ENOENT") throw new Error(`File not found: ${ffmpegPath}`);
    if (e.code === "EACCES") throw new Error(`Permission denied: ${ffmpegPath}`);
    throw new Error(e.message || "Unknown error");
  }
}

interface ConvertOpts {
  ffmpegPath: string;
  target: VideoTarget;
  quality: number;       // 1-100
  resizeValue?: number;  // max dimension (0 = no resize)
}

export async function convertVideo(
  inputData: ArrayBuffer,
  inputExt: string,
  opts: ConvertOpts,
): Promise<{ data: ArrayBuffer; ext: string } | null> {
  if (opts.target === "disabled" || !opts.ffmpegPath) return null;

  const tmpDir = await mkdtempAsync(path.join(os.tmpdir(), "attachhub-"));
  const inFile = path.join(tmpDir, `input.${inputExt}`);
  const outExt = opts.target;
  const outFile = path.join(tmpDir, `output.${outExt}`);

  try {
    await writeFileAsync(inFile, Buffer.from(inputData));

    const args = buildFFmpegArgs(inFile, outFile, inputExt, opts);
    await execFileAsync(opts.ffmpegPath, args, { timeout: 120_000 });

    const result = await readFileAsync(outFile);
    return { data: result.buffer.slice(result.byteOffset, result.byteOffset + result.byteLength), ext: outExt };
  } catch (e: unknown) {
    console.error("[AttachHub] FFmpeg conversion failed:", e.message);
    return null;
  } finally {
    try { await unlinkAsync(inFile); } catch (_) {}
    try { await unlinkAsync(outFile); } catch (_) {}
    try { fs.rmdirSync(tmpDir); } catch (_) {}
  }
}

function buildFFmpegArgs(
  inFile: string,
  outFile: string,
  inputExt: string,
  opts: ConvertOpts,
): string[] {
  const args = ["-y", "-i", inFile];
  const q = Math.max(1, Math.min(100, opts.quality));

  if (opts.target === "webp") {
    args.push("-vcodec", "libwebp");
    args.push("-lossless", "0");
    // libwebp quality: 0-100 (higher = better)
    args.push("-q:v", String(q));
    args.push("-loop", "0");
    args.push("-an"); // strip audio for animated webp
    if (opts.resizeValue && opts.resizeValue > 0) {
      args.push("-vf", `scale='min(${opts.resizeValue},iw)':'min(${opts.resizeValue},ih)':force_original_aspect_ratio=decrease`);
    }
  } else if (opts.target === "gif") {
    const filters: string[] = [];
    if (opts.resizeValue && opts.resizeValue > 0) {
      filters.push(`scale='min(${opts.resizeValue},iw)':'min(${opts.resizeValue},ih)':force_original_aspect_ratio=decrease:flags=lanczos`);
    }
    filters.push("split[s0][s1]");
    filters.push("[s0]palettegen=max_colors=256[p]");
    filters.push("[s1][p]paletteuse=dither=bayer:bayer_scale=5");
    args.push("-filter_complex", filters.join(","));
    args.push("-loop", "0");
  }

  args.push(outFile);
  return args;
}

export interface StillConvertOpts {
  ffmpegPath: string;
  targetExt: string;   // "webp" | "jpg" | "png"
  quality: number;
  resizeValue?: number;
}

/**
 * Convert a still image (e.g. HEIC) to a standard format using FFmpeg.
 * Extracts a single frame — no animation, no loop.
 */
export async function convertImageWithFFmpeg(
  absPath: string,
  opts: StillConvertOpts,
): Promise<{ data: ArrayBuffer; ext: string } | null> {
  if (!opts.ffmpegPath) return null;

  const tmpDir = await mkdtempAsync(path.join(os.tmpdir(), "attachhub-"));
  const outExt = opts.targetExt;
  const outFile = path.join(tmpDir, `output.${outExt}`);

  try {
    const args = ["-y", "-i", absPath, "-frames:v", "1"];
    const q = Math.max(1, Math.min(100, opts.quality));

    if (outExt === "webp") {
      args.push("-vcodec", "libwebp", "-lossless", "0", "-q:v", String(q));
    } else if (outExt === "jpg") {
      args.push("-q:v", String(Math.round(31 - (q / 100) * 29)));
    }
    // png needs no quality flag

    if (opts.resizeValue && opts.resizeValue > 0) {
      args.push("-vf", `scale='min(${opts.resizeValue},iw)':'min(${opts.resizeValue},ih)':force_original_aspect_ratio=decrease`);
    }

    args.push(outFile);
    await execFileAsync(opts.ffmpegPath, args, { timeout: 30_000 });
    const result = await readFileAsync(outFile);
    return { data: result.buffer.slice(result.byteOffset, result.byteOffset + result.byteLength), ext: outExt };
  } catch (e: unknown) {
    console.error("[AttachHub] FFmpeg image conversion failed:", e.message);
    return null;
  } finally {
    try { await unlinkAsync(outFile); } catch (_) {}
    try { fs.rmdirSync(tmpDir); } catch (_) {}
  }
}

/**
 * Convert a video file that already exists on disk (by vault absolute path).
 * Returns the converted data + new extension, or null if conversion not needed/failed.
 */
export async function convertVideoFile(
  absPath: string,
  inputExt: string,
  opts: ConvertOpts,
): Promise<{ data: ArrayBuffer; ext: string } | null> {
  if (opts.target === "disabled" || !opts.ffmpegPath) return null;

  const tmpDir = await mkdtempAsync(path.join(os.tmpdir(), "attachhub-"));
  const outExt = opts.target;
  const outFile = path.join(tmpDir, `output.${outExt}`);

  try {
    const args = buildFFmpegArgs(absPath, outFile, inputExt, opts);
    await execFileAsync(opts.ffmpegPath, args, { timeout: 120_000 });
    const result = await readFileAsync(outFile);
    return { data: result.buffer.slice(result.byteOffset, result.byteOffset + result.byteLength), ext: outExt };
  } catch (e: unknown) {
    console.error("[AttachHub] FFmpeg file conversion failed:", e.message);
    return null;
  } finally {
    try { await unlinkAsync(outFile); } catch (_) {}
    try { fs.rmdirSync(tmpDir); } catch (_) {}
  }
}

import { Plugin, TFile, normalizePath } from "obsidian";
import { AttachmentHubSettings } from "./settings";
import {
  pDir,
  parseFM, fmSection, replaceFMField,
  writeFM, getFM,
  stripLink, fmtPath,
  extractResolvedPaths,
} from "./utils";

export class FrontmatterSync {
  private plugin: Plugin;
  private settings: AttachmentHubSettings;
  private _writing: Set<string>;
  private _noteFields: Map<string, Map<string, string>>;
  private _mdxHash: Map<string, string>;

  constructor(
    plugin: Plugin, 
    settings: AttachmentHubSettings, 
    writing: Set<string>,
    noteFields: Map<string, Map<string, string>>,
    mdxHash: Map<string, string>
  ) {
    this.plugin = plugin;
    this.settings = settings;
    this._writing = writing;
    this._noteFields = noteFields;
    this._mdxHash = mdxHash;
  }

  async onFMChange(file: TFile): Promise<void> {
    const fm = this.plugin.app.metadataCache.getFileCache(file)?.frontmatter;
    if (!fm) return;
    this.updateNoteIndex(file.path, extractResolvedPaths(fm, this.settings.trackedFields, pDir(file.path)));
    await this._autoProcessFM(file, fm, null);
  }

  async onMdxModify(file: TFile): Promise<void> {
    let content: string;
    try { content = await this.plugin.app.vault.cachedRead(file); } catch (_) { return; }
    const section = fmSection(content);
    if (!section || this._mdxHash.get(file.path) === section) return;
    this._mdxHash.set(file.path, section);
    const fm = parseFM(content);
    if (!fm) return;
    this.updateNoteIndex(file.path, extractResolvedPaths(fm, this.settings.trackedFields, pDir(file.path)));
    await this._autoProcessFM(file, fm, content);
  }

  private async _autoProcessFM(file: TFile, fm: Record<string, unknown>, content: string | null): Promise<void> {
    const fmt = this.settings.pathFormat || "plain";
    const noteDir = pDir(file.path);
    const upd: Record<string, string> = {};
    for (const field of this.settings.trackedFields) {
      const val = fm[field];
      if (typeof val !== "string" || !val) continue;
      const plain = stripLink(val) || val;
      if (plain.startsWith("http")) continue;
      const resolved = this.resolve(noteDir, plain);
      if (!resolved) continue;
      const formatted = fmtPath(this.relative(noteDir, resolved), fmt);
      if (formatted !== val) upd[field] = formatted;
    }
    if (!Object.keys(upd).length) return;
    this._writing.add(file.path);
    try {
      if (content && file.extension !== "md") {
        let c = content;
        for (const [k, v] of Object.entries(upd)) c = replaceFMField(c, k, v);
        if (c !== content) await this.plugin.app.vault.modify(file, c);
      } else {
        await writeFM(this.plugin.app, file, upd);
      }
    } finally {
      setTimeout(() => this._writing.delete(file.path), 2000);
    }
    const newFM = await getFM(this.plugin.app, file);
    if (newFM) this.updateNoteIndex(file.path, extractResolvedPaths(newFM, this.settings.trackedFields, noteDir));
  }

  async handleAttachRename(file: TFile, oldPath: string): Promise<void> {
    const normOld = normalizePath(oldPath), normNew = normalizePath(file.path);
    const notes = this.getNotesFor(normOld);
    if (!notes.size) return;
    for (const notePath of notes) {
      const nf = this.plugin.app.vault.getAbstractFileByPath(notePath);
      if (!nf || !(nf instanceof TFile)) continue;
      const fm = await getFM(this.plugin.app, nf);
      if (!fm) continue;
      const noteDir = pDir(notePath);
      const upd: Record<string, string> = {};
      for (const field of this.settings.trackedFields) {
        const val = fm[field];
        if (typeof val !== "string" || !val) continue;
        const p = stripLink(val) || val;
        const r = this.resolve(noteDir, p);
        if (r && normalizePath(r) === normOld)
          upd[field] = fmtPath(this.relative(noteDir, normNew), this.settings.pathFormat || "plain");
      }
      if (Object.keys(upd).length) {
        this._writing.add(notePath);
        try { await writeFM(this.plugin.app, nf, upd); } finally {
          setTimeout(() => this._writing.delete(notePath), 2000);
        }
        const newMap = new Map<string, string>();
        for (const [fld, ap] of this._noteFields.get(notePath) || new Map()) {
          newMap.set(fld, normalizePath(ap) === normOld ? normNew : ap);
        }
        this.updateNoteIndex(notePath, newMap);
      }
    }
  }

  async handleNoteMove(file: TFile, oldPath: string): Promise<void> {
    const oldDir = pDir(oldPath), newDir = pDir(file.path);
    if (oldDir === newDir) return;

    // Brief delay: let Obsidian finish its own link updates for .md files
    await new Promise(r => setTimeout(r, 300));

    const freshFile = this.plugin.app.vault.getAbstractFileByPath(file.path);
    if (!(freshFile instanceof TFile)) return;

    let content: string;
    try { content = await this.plugin.app.vault.read(freshFile); } catch (_) { return; }

    let changed = false;

    // ── 1. Update frontmatter tracked fields ──
    const fm = parseFM(content);
    if (fm) {
      for (const field of this.settings.trackedFields) {
        const val = fm[field];
        if (typeof val !== "string" || !val) continue;
        const plain = stripLink(val) || val;
        const newRel = this._rewriteRelPath(oldDir, newDir, plain);
        if (newRel) {
          const formatted = fmtPath(newRel, this.settings.pathFormat || "plain");
          content = replaceFMField(content, field, formatted);
          changed = true;
        }
      }
    }

    // ── 2. Update body relative links ──
    // Markdown image/links: ![alt](path) or [text](path)
    content = content.replace(
      /(!?\[[^\]]*\])\(([^)]+)\)/g,
      (_match, prefix: string, linkPath: string) => {
        const trimmed = linkPath.split(/\s+["']/)[0]; // strip title like "title"
        const newRel = this._rewriteRelPath(oldDir, newDir, trimmed);
        if (!newRel) return _match;
        changed = true;
        const rest = linkPath.slice(trimmed.length);
        return `${prefix}(${encodeURI(newRel)}${rest})`;
      },
    );

    // Wikilinks with relative paths: ![[../path/file]] or [[../path/file]]
    content = content.replace(
      /(!?\[\[)([^\]|]+)((?:\|[^\]]*)?)\]\]/g,
      (_match, open: string, linkPath: string, alias: string) => {
        if (!linkPath.includes("/")) return _match; // short name, not a path
        const newRel = this._rewriteRelPath(oldDir, newDir, linkPath);
        if (!newRel) return _match;
        changed = true;
        return `${open}${newRel}${alias}]]`;
      },
    );

    if (changed) {
      this._writing.add(freshFile.path);
      try {
        await this.plugin.app.vault.modify(freshFile, content);
      } finally {
        setTimeout(() => this._writing.delete(freshFile.path), 2000);
      }
      const newFM = parseFM(content);
      if (newFM) this.updateNoteIndex(freshFile.path, extractResolvedPaths(newFM, this.settings.trackedFields, newDir));
    }
  }

  async onAttachDelete(file: TFile): Promise<void> {
    const dp = normalizePath(file.path);
    const notes = this.getNotesFor(dp);
    if (!notes.size) return;
    let n = 0;
    for (const notePath of notes) {
      const nf = this.plugin.app.vault.getAbstractFileByPath(notePath);
      if (!nf || !(nf instanceof TFile)) continue;
      const fm = await getFM(this.plugin.app, nf);
      if (!fm) continue;
      const noteDir = pDir(notePath);
      const clr: Record<string, string> = {};
      for (const field of this.settings.trackedFields) {
        const val = fm[field];
        if (typeof val !== "string" || !val) continue;
        const p = stripLink(val) || val;
        const r = this.resolve(noteDir, p);
        if (r && normalizePath(r) === dp) clr[field] = "";
      }
      if (Object.keys(clr).length && (await writeFM(this.plugin.app, nf, clr))) n++;
    }
    this.removeFromIndex(dp);
  }

  private _rewriteRelPath(oldDir: string, newDir: string, relPath: string): string | null {
    if (!relPath || relPath.startsWith("http://") || relPath.startsWith("https://")) return null;
    const decoded = decodeURI(relPath);
    const abs = this.resolve(oldDir, decoded);
    if (!abs) return null;
    if (!this.plugin.app.vault.getAbstractFileByPath(abs)) return null;
    const newRel = this.relative(newDir, abs);
    return newRel === decoded ? null : newRel;
  }

  // Helper methods that will be implemented in the main plugin
  private resolve(fromDir: string, rel: string): string | null {
    if (!rel || rel.startsWith("http://") || rel.startsWith("https://")) return null;
    const s = fromDir ? fromDir.split("/") : [];
    for (const p of rel.split("/")) {
      if (p === "..") s.pop();
      else if (p !== "." && p) s.push(p);
    }
    return normalizePath(s.join("/"));
  }

  private relative(fromDir: string, toPath: string): string {
    const f = fromDir ? fromDir.split("/") : [];
    const t = toPath.split("/");
    let c = 0;
    while (c < f.length && c < t.length && f[c] === t[c]) c++;
    const p: string[] = [];
    for (let i = 0; i < f.length - c; i++) p.push("..");
    p.push(...t.slice(c));
    return p.join("/");
  }

  private updateNoteIndex(notePath: string, newMap: Map<string, string> | null): void {
    // This will be implemented in the main plugin
  }

  private getNotesFor(ap: string): Set<string> {
    // This will be implemented in the main plugin
    return new Set();
  }

  private removeFromIndex(ap: string): void {
    // This will be implemented in the main plugin
  }
}

/**
 * HEIC/HEIF decoder using heic2any.
 * Converts static HEIC images to PNG for further Canvas API processing.
 */

import heic2any from "heic2any";

export async function decodeHeic(data: ArrayBuffer): Promise<ArrayBuffer | null> {
  try {
    const blob = new Blob([data], { type: "image/heic" });
    const result = await (heic2any)({ blob, toType: "image/png", multiple: false });
    const outBlob = Array.isArray(result) ? result[0] : result;
    return await outBlob.arrayBuffer();
  } catch (e) {
    console.error("[AttachHub] HEIC decode failed:", e);
    return null;
  }
}

